kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int l = get_global_id(0);

    if(l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0*alpha*alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    for(int k=0; k<(1+box[l].nn); k++){
        int pointer;
        if(k==0){
            pointer = l;
        }
        else{
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for(int i=0; i<NUMBER_PAR_PER_BOX; i++){
            for(int j=0; j<NUMBER_PAR_PER_BOX; j++){
                fp r2 = rA[i].v + rB[j].v - DOT(rA[i],rB[j]);
                fp u2 = a2*r2;
                fp vij = exp(-u2);
                fp fs = 2.0*vij;

                THREE_VECTOR d;
                d.x = rA[i].x - rB[j].x;
                d.y = rA[i].y - rB[j].y;
                d.z = rA[i].z - rB[j].z;

                fp fxij = fs*d.x;
                fp fyij = fs*d.y;
                fp fzij = fs*d.z;

                fA[i].v += qB[j]*vij;
                fA[i].x += qB[j]*fxij;
                fA[i].y += qB[j]*fyij;
                fA[i].z += qB[j]*fzij;
            }
        }
    }
}
